 1	import React, { FC } from 'react';
 2	
 3	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 4	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { PATHS_TO_HIGHLIGHT } from '@kubevirt-utils/resources/vm/utils/constants';
 7	import { PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 8	
 9	import { onSubmitYAML } from '../details/utils/utils';
10	import { ConfigurationInnerTabProps } from '../utils/types';
11	
12	import AddNetworkInterfaceButton from './components/AddNetworkInterfaceButton';
13	import NetworkInterfaceList from './components/list/NetworkInterfaceList';
14	
15	import './network-tab.scss';
16	
17	const NetworkTab: FC<ConfigurationInnerTabProps> = ({ vm, vmi }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  return (
21	    <SidebarEditor
22	      onResourceUpdate={onSubmitYAML}
23	      pathsToHighlight={PATHS_TO_HIGHLIGHT.NETWORK_TAB}
24	      resource={vm}
25	    >
26	      <PageSection variant={PageSectionVariants.light}>
27	        <Title headingLevel="h2">
28	          <SearchItem id="network">{t('Network interfaces')}</SearchItem>
29	        </Title>
30	        <AddNetworkInterfaceButton vm={vm} vmi={vmi} />
31	        <NetworkInterfaceList vm={vm} vmi={vmi} />
32	      </PageSection>
33	    </SidebarEditor>
34	  );
35	};
36	
37	export default NetworkTab;

